use strict;
use warnings;

sub bubble_sort {
    my @arr = @_;
    my $n = scalar(@arr);

    for my $i (0 .. $n - 2) {
        for my $j (0 .. $n - $i - 2) {
            if ($arr[$j] > $arr[$j + 1]) {
                ($arr[$j], $arr[$j + 1]) = ($arr[$j + 1], $arr[$j]);
            }
        }
    }
    return @arr;
}

my @numbers = (64, 34, 25, 12, 22, 11, 90);
print "Siralanmamis dizi: @numbers\n";

my @sorted_numbers = bubble_sort(@numbers);
print "Siralanmis dizi: @sorted_numbers\n";

